<?php
namespace App\Http\Controllers;
use App\Http\Requests\CreateHybridHostingProjectRequest; use App\Jobs\RunSiteDeployment; use App\Models\Site; use App\Services\Hosting\AuditLogger; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\File; use Illuminate\Support\Str;
class HybridHostingProjectController extends Controller {
 public function index(Request $r):JsonResponse{return response()->json(['projects'=>$r->user()->sites()->where('stack','Node.js + Laravel')->with(['deployments'=>fn($q)=>$q->latest()->limit(1)])->latest()->get()]);}
 public function store(CreateHybridHostingProjectRequest $r,AuditLogger $audit):JsonResponse{$v=$r->validated();$slug=Str::slug($v['name']);if($r->user()->sites()->where('slug',$slug)->exists())return response()->json(['message'=>'You already have a project with this name.'],422);if(!$r->user()->linux_username)$r->user()->update(['linux_username'=>'user_'.$r->user()->id]);$root=rtrim((string)config('berrypanel.users_root'),'/').'/'.$r->user()->linux_username.'/sites/'.$slug;File::ensureDirectoryExists($root,0775,true);$site=Site::create([...$v,'user_id'=>$r->user()->id,'slug'=>$slug,'stack'=>'Node.js + Laravel','status'=>'queued','root_path'=>$root,'public_path'=>$root.'/'.ltrim($v['laravel_public_directory'],'/'),'local_url'=>$v['domain']]);$deployment=$site->deployments()->create(['triggered_by'=>$r->user()->id,'status'=>'queued','branch'=>$site->repository_branch]);RunSiteDeployment::dispatch($deployment->id);$audit->record('hybrid-project.created',$site,$r->user(),['deployment_id'=>$deployment->id]);return response()->json(['project'=>$site,'deployment'=>$deployment],202);}
}
